INSERT INTO public.events VALUES ('a2488c48-12bc-48cc-ab4f-6820d4e86b6d', 'Afro Nation Ouaga 2025', 'Experience the biggest Afrobeats festival in West Africa! Afro Nation returns to Ouagadougou with an incredible lineup featuring top African artists, amazing food, and unforgettable performances. Join thousands of music lovers for this three-day celebration of African music and culture.', '2026-06-10', '18:00', 'Stade Municipal de Ouagadougou', 'Stade Municipal', 'https://images.unsplash.com/photo-1470229722913-7c0e2dbbafd3', 2000, 'XOF', 2500, 0, 'CANCELLED', false, '2025-05-13 06:50:04.023245+00', '2026-04-08 04:13:02.154559+00', 0, 0, NULL, '{"latitude": 12.3714, "longitude": -1.5197}', NULL, true, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.events VALUES ('22b29ce7-61ee-43b5-b954-db93ec19ed8d', 'INTÉGRATION NIGHT ', 'L’Intégration Night est une soirée de bienvenue des étudiants organisée par le Bureau Général des Étudiants (BGE) de l’ISPP Campus Koulouba. L’événement aura lieu sur le campus, dans une ambiance festive et conviviale dédiée à l’intégration des étudiants.
INSERT INTO public.events VALUES ('20318e3e-a845-4997-bae1-c5296891fbaa', 'THE OASIS', 'The Oasis est un événement unique qui se tiendra du 1er au 2 mai 2026 à L’Oasis Wakati, situé à Kalgodin, non loin de la Brigade des Sapeurs Pompiers. Accessible gratuitement, cet événement propose une expérience immersive axée sur la détente, les connexions de qualité et la découverte de marques.
INSERT INTO public.events VALUES ('a93c06a3-1bc4-45a8-bde0-8ffeb3b76d8e', 'Aqua Chill – Mousse Party', 'L’événement Aqua Chill – Mousse Party promet une ambiance rafraîchissante et festival à l’Espace Joanna. Organisé par DAF Event, ce rendez-vous est dédié aux amateurs de détente, de musique et de fun autour d’une grande piscine à mousse.
INSERT INTO public.events VALUES ('5b4bb152-e2d2-4e90-87f1-89225123c89b', 'SUN & FUN – OUAGA', 'Sun & Fun Ouaga – une journée exceptionnelle de détente, piscine, musique et animation le 26 avril à La Plénitude', '2026-04-26', '10:00', 'LA PLÉNITUDE', '', 'https://uwmlagvsivxqocklxbbo.supabase.co/storage/v1/object/public/event-images/event-images/ngif67zma3-1775668188306.jpeg', 3000, 'XOF', 200, 0, 'DRAFT', true, '2026-04-08 17:11:32.285385+00', '2026-04-08 17:11:32.285385+00', 0, 0, NULL, '{"latitude": 12.3714, "longitude": -1.5197}', NULL, true, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
